INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('94f3832d-582d-4a03-a940-6fae6d7fb81f', 'Push-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Start in a high plank position with your hands under your shoulders. Lower your body until your chest nearly touches the floor. Push back up to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('c6b382c9-b2ea-4649-9cdd-76d4e9c0b74c', 'Squats', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Stand with feet shoulder-width apart. Lower your body as if sitting back into a chair, keeping your chest up. Return to standing.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('0bfce319-c414-42af-ace1-9e704f697679', 'Plank', 'STRENGTH_MOBILITY'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Transverse Abdominis"}', 'Start in a forearm plank position with your elbows directly under your shoulders. Keep your body in a straight line from head to heels.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('60fa5f73-341b-4757-befd-59d5a62f5217', 'Deadlift', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Glutes, Hamstrings, Lower Back"}', 'Stand with feet hip-width apart, barbell in front of you. Bend at the hips and knees to grasp the bar, then lift it by straightening your hips and knees.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('747f95bf-ca85-4237-b28f-80ac6bd319dc', 'Bicep Curls', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Biceps, Forearms"}', 'Stand with a dumbbell in each hand, arms fully extended. Curl the weights up to your shoulders while keeping your elbows close to your torso.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b526feba-c8f5-43fa-babd-f409674b61c1', 'Kettlebell Swing', 'STRENGTH_CARDIO'::"ExerciseType", 'KETTLEBELL'::"EquipmentType", 'CORE'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Hamstrings, Shoulders"}', 'Stand with feet slightly wider than shoulder-width. Swing the kettlebell between your legs and then up to shoulder height by driving your hips forward.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('33b6bbfe-ed42-4460-b623-3c18e2b47fd5', 'Shoulder Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Triceps"}', 'Hold a dumbbell in each hand at shoulder height, then press them overhead until your arms are fully extended. Lower back to shoulder height.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('0a9af9e8-2a8d-43eb-a65b-224acfcceccd', 'Lat Pulldown', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Sit at the lat pulldown machine, grasp the bar with a wide grip, and pull it down to your chest. Slowly return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('796ba078-a830-4450-9dd8-4235e0e7fdef', 'Hamstring Stretch', 'MOBILITY'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'STRETCH'::"MovementType", '{"Hamstrings"}', 'Stand upright and place one heel on a bench or step. Lean forward slightly to feel a stretch in the hamstring of the elevated leg.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('bf88cfc3-e904-4485-8b83-8443f1168715', 'Jumping Jacks', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Calves, Deltoids, Glutes"}', 'Stand upright with feet together and arms at your sides. Jump your feet out while raising your arms overhead, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('9650b7ed-e241-4198-8570-1e60ec066580', 'Bench Press', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Lie flat on a bench with a barbell. Lower the bar to your chest and push it back up to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('09e32b7c-53bc-4bd0-ac6f-926540ca3ba6', 'Lunges', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Step forward with one leg and lower your hips until both knees are bent at a 90-degree angle. Push back to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('50f2689c-2bd3-434f-98d9-9546d2fe5009', 'Pull-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Grasp a pull-up bar with an overhand grip. Pull your body up until your chin is above the bar, then lower back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('64a0a069-fa72-48b5-8951-44ac465b63ff', 'Mountain Climbers', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'PUSH'::"MovementType", '{"Rectus Abdominis, Hip Flexors, Deltoids"}', 'Start in a plank position and alternate driving your knees towards your chest as quickly as possible.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('ec2405f4-adcc-4b04-b95b-a6dcde98e6c5', 'Leg Raises', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Lie on your back with your legs extended. Lift your legs until they are perpendicular to the floor, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('0989b0bc-7909-45e8-abaf-ba320e87b88a', 'Tricep Dips', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Triceps, Deltoids"}', 'Place your hands behind you on a bench or chair. Lower your body by bending your elbows, then push back up to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('503c97d1-6102-4434-875e-2db26c29c4d8', 'Russian Twists', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'PUSH'::"MovementType", '{"Obliques, Rectus Abdominis"}', 'Sit on the floor with your knees bent, lean back slightly, and twist your torso to each side, tapping the floor with your hands.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('f61b3cb7-d20d-4868-8f46-3146e3bb1e4c', 'Burpees', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Quadriceps, Core"}', 'Start in a standing position, drop into a squat, kick your feet back into a plank, return to the squat position, and jump up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('71c5a5de-74e1-48d6-bc54-11c96843e3d5', 'Dumbbell Rows', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'With a dumbbell in each hand, bend at the waist with your back straight. Pull the dumbbells towards your torso, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('09bfa704-27d2-4cf8-954b-a6e89b6e0dd9', 'Goblet Squats', 'STRENGTH'::"ExerciseType", 'KETTLEBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Hold a kettlebell at chest level and squat down as if sitting in a chair. Return to standing.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5776c17f-f72d-4bbc-a43a-836a9eb14713', 'Glute Bridge', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Hamstrings"}', 'Lie on your back with knees bent and feet flat on the floor. Lift your hips until your body forms a straight line from shoulders to knees.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('c0dd24a4-7b6d-4846-a944-5818ce317bbd', 'Overhead Tricep Extension', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Triceps"}', 'Hold a dumbbell with both hands overhead, then lower it behind your head by bending your elbows. Extend your arms back to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b98a1cee-ab38-4c2c-95b1-5b8e0575bfb9', 'Side Plank', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Obliques, Shoulders"}', 'Lie on one side with your legs straight. Lift your hips so your body forms a straight line, supporting yourself on one forearm.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('2bd396d4-fa0d-4069-885e-122debbdd839', 'Cable Flyes', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals"}', 'Stand in the middle of a cable machine with handles in each hand. With a slight bend in your elbows, bring your hands together in front of your chest.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('58db8d08-6b19-47fc-b175-e5ea03ff4188', 'Step-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes"}', 'Step onto a bench or box with one foot, then push through that foot to lift your body up. Step back down and repeat on the other side.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b1b2a258-7663-412d-8db0-d6c2392d7403', 'Barbell Rows', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Stand with feet hip-width apart, bend forward at the hips, and row the barbell towards your torso. Lower it back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('21cf20d0-1408-4df2-a0aa-f31c2449ac2a', 'Chest Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Lie on a bench with a dumbbell in each hand. Press the weights straight up over your chest, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('d4438ff9-6c63-4f34-a43d-07c8492dd63b', 'Box Jumps', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Calves"}', 'Stand in front of a sturdy box or bench. Jump onto the box, landing softly, then step back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('c6b27e26-43ac-4170-b2de-51d4e45f9011', 'Hanging Leg Raises', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Hang from a pull-up bar and raise your legs until they are parallel to the floor. Lower them back down slowly.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('31195fd1-9019-4031-99d9-177db194363a', 'Farmer''s Walk', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'HOLD'::"MovementType", '{"Forearms, Shoulders, Core"}', 'Hold a heavy dumbbell in each hand at your sides and walk forward while maintaining a straight posture.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5e0fc8fb-b415-4a50-a632-d6bd39a14c1f', 'Calf Raises', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Calves"}', 'Stand with the balls of your feet on the edge of a step. Raise your heels as high as possible, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('f2fa8183-d9df-4276-aa79-509060061576', 'Battle Ropes', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Forearms, Core"}', 'Hold the ends of the ropes in each hand. Alternate waves with your arms to move the ropes up and down as quickly as possible.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('13e15e53-cfc9-43c9-83fc-f5a548673485', 'Medicine Ball Slams', 'STRENGTH_CARDIO'::"ExerciseType", 'MEDICINE_BALL'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Core, Shoulders, Glutes"}', 'Lift a medicine ball overhead and slam it down on the ground with as much force as possible. Catch it on the rebound and repeat.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('943941fb-ba21-4ecf-bb54-cd42c331fd24', 'Dumbbell Deadlift', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Glutes, Hamstrings, Lower Back"}', 'Stand with feet hip-width apart, holding a dumbbell in each hand. Bend at the hips and knees to lower the weights, then lift back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('f5386a59-4611-4642-9076-fd119d3b56ae', 'Push Press', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Triceps"}', 'Hold a barbell at shoulder height. Use your legs to help press the bar overhead, then lower it back to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('1b93d495-0b50-425f-9c9c-2a0cdf03be33', 'Treadmill Run', 'CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Hamstrings, Calves"}', 'Run on a treadmill at a speed and incline that challenges your endurance.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('154a9fdc-8d70-40b6-a4ed-71247cb35441', 'Incline Dumbbell Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Lie on an incline bench with a dumbbell in each hand. Press the weights up and together over your chest, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b356f33f-a710-4679-938b-b8b7acb8bc27', 'Renegade Rows', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps, Core"}', 'Start in a plank position with a dumbbell in each hand. Row one dumbbell towards your torso while balancing on the other hand.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('0743fe24-65f3-4257-826f-f486f75689e6', 'Leg Press', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Sit on a leg press machine with your feet shoulder-width apart on the platform. Push the platform away by extending your legs.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5c01ecb7-4f6f-4fb9-98e6-71dfbd191c43', 'Cable Tricep Pushdown', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Triceps"}', 'Stand facing a cable machine with a high pulley. Push the handle downwards until your arms are fully extended.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('0528976a-d4ab-4393-8b9a-4dd5045ba67d', 'Single-Leg Deadlift', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Hamstrings, Glutes, Lower Back"}', 'Stand on one leg, holding a dumbbell in the opposite hand. Bend at the hips to lower the weight while extending the free leg behind you.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b5eef03c-6a4d-49ca-ac45-ba1e26e81cc1', 'Inverted Rows', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Lie under a bar or suspension trainer, pull your chest towards the bar while keeping your body straight, then lower back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('f11f74f4-f490-45b9-911a-887558caa1d7', 'Pallof Press', 'STRENGTH_MOBILITY'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Obliques, Transverse Abdominis"}', 'Stand sideways to a cable machine with the handle at chest height. Push the handle straight out in front of you, resisting the rotation.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b9193b60-87dd-4635-8498-4dbd7d943379', 'Kettlebell Deadlift', 'STRENGTH'::"ExerciseType", 'KETTLEBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Glutes, Hamstrings, Lower Back"}', 'Stand with feet shoulder-width apart, kettlebell between your feet. Bend at the hips and knees to lift the kettlebell off the ground.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('a32ba731-6c04-410c-b664-7b4c30532aae', 'Hanging Knee Tucks', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Hang from a pull-up bar and tuck your knees towards your chest, then slowly lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('c950e6df-02be-45ca-a8bb-4d304f948b97', 'Resistance Band Pull Aparts', 'STRENGTH'::"ExerciseType", 'RESISTANCE_BAND'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Rear Deltoids, Trapezius, Rhomboids"}', 'Hold a resistance band in front of you with arms extended. Pull the band apart by bringing your hands out to your sides.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('97cdae67-762f-4569-8271-b7b67e2a0616', 'Bulgarian Split Squats', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Stand lunge-style with one foot behind you on a bench. Lower your hips until your front thigh is parallel to the floor, then push back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('1c2f85f8-dedf-4beb-ba39-886fc3513eeb', 'Seated Shoulder Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Triceps"}', 'Sit on a bench with a dumbbell in each hand at shoulder height. Press the weights overhead until your arms are fully extended.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5710f013-86f3-4ef6-b0a9-72dd23916a2c', 'Incline Push-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Place your hands on an elevated surface like a bench. Lower your chest towards the surface, then push back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('517d9c55-52ce-469a-b875-ba03d2a38bb7', 'Hip Thrusts', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Hamstrings"}', 'Sit on the ground with your upper back against a bench, barbell across your hips. Lift your hips towards the ceiling by squeezing your glutes.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('14ecd906-3883-4d55-bc28-e9737d8585ca', 'Barbell Curl', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Biceps, Forearms"}', 'Stand with feet shoulder-width apart, holding a barbell with an underhand grip. Curl the bar towards your shoulders, then lower it back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('bba15145-cc45-4801-b6d3-0c1e340dd7f4', 'Cable Row', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Sit at a cable row machine with feet braced. Pull the handle towards your torso, then slowly return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('33e3a520-4a64-4c6b-ab41-9c1de3171b64', 'Plank Shoulder Taps', 'STRENGTH_MOBILITY'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Obliques, Deltoids"}', 'Start in a high plank position. Tap one hand to the opposite shoulder, then switch sides, while keeping your body stable.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('9b7d7db5-5200-42be-bf30-9df72b5f6b54', 'Dumbbell Lateral Raise', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids"}', 'Stand with a dumbbell in each hand, arms at your sides. Raise your arms out to the sides until they are parallel to the floor.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('1ffdc04b-1a8f-4026-8bf7-cb424edd0922', 'Wall Sit', 'STRENGTH_MOBILITY'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'HOLD'::"MovementType", '{"Quadriceps, Glutes"}', 'Lean against a wall with your feet shoulder-width apart. Slide down until your knees are at a 90-degree angle and hold the position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('1bf07f95-7920-4ce1-a6b5-af97977ab12e', 'Spider Plank', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Obliques"}', 'Start in a forearm plank position. Bring one knee to the outside of your elbow, then return to the starting position and repeat on the other side.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('ae1367aa-75a9-48cf-be8d-01f097612247', 'Sumo Deadlift', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Glutes, Hamstrings, Lower Back"}', 'Stand with a wide stance, toes pointing out. Grasp the barbell with hands inside your knees, and lift it by extending your hips and knees.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('8fc678ce-a728-454f-a8e2-87eff41aefbf', 'Single Arm Dumbbell Row', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Place one knee and hand on a bench for support, row the dumbbell towards your torso with the other hand.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('921b3ba2-cf6f-49fe-9af4-ee91fbb49fd3', 'Kettlebell Clean and Press', 'STRENGTH'::"ExerciseType", 'KETTLEBELL'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Shoulders, Triceps"}', 'Swing the kettlebell up to shoulder height, then press it overhead. Lower it back down and repeat.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('7da1ceed-a8d1-4628-9045-d101625342a8', 'Jump Rope', 'CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Calves, Shoulders"}', 'Jump over the rope as it passes under your feet, keeping a steady rhythm.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('2b5178ec-9a50-4f4c-be9d-8d100255a735', 'Side Lunge', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Adductors"}', 'Step out to the side, bending one knee while keeping the other leg straight. Push back to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('28850597-31bc-47d1-a911-3d022d98541a', 'Machine Chest Fly', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals"}', 'Sit at a chest fly machine, grasp the handles, and bring them together in front of your chest, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('72fc60ef-b4b1-4659-8f19-09a36ea50edc', 'Hack Squat', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Stand on a hack squat machine platform, lower your body by bending your knees, then push back up to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('99c1a710-d37e-40b1-b1c7-a78df97c608b', 'Decline Push-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Place your feet on an elevated surface, hands on the floor. Lower your chest towards the floor, then push back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('d6e2725e-8a54-49ac-90fa-5334fc12db12', 'Band Face Pull', 'STRENGTH'::"ExerciseType", 'RESISTANCE_BAND'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Rear Deltoids, Trapezius, Rhomboids"}', 'Attach a resistance band to a high anchor. Pull the band towards your face, leading with your elbows.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('ed24cd2f-8335-4b85-bd85-4d0488ff30fb', 'Ab Wheel Rollout', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'PUSH'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Kneel on the floor with an ab wheel in front of you. Roll the wheel forward while keeping your core tight, then roll back.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('9f0a6763-2f59-47ca-83ca-bd82e62efc5d', 'Side Leg Raises', 'MOBILITY'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'HOLD'::"MovementType", '{"Glutes, Hip Flexors"}', 'Lie on your side with legs straight. Lift your top leg towards the ceiling, then lower it back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('70ace2b3-fd4b-491f-8537-737d3c7efd8f', 'Romanian Deadlift', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Hamstrings, Glutes, Lower Back"}', 'Hold a barbell in front of your thighs. Bend at the hips to lower the bar down your legs, then return to standing.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('adaa6636-7412-4a67-b808-386aa847fe1d', 'Arnold Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Triceps"}', 'Hold dumbbells at shoulder height, palms facing you. Rotate your arms as you press the weights overhead, ending with palms facing forward.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('3961afd1-ada9-4428-a660-68a5bce83d9c', 'Landmine Press', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Deltoids, Triceps"}', 'Hold the end of a barbell anchored in a landmine attachment. Press the bar overhead with one arm.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b105d0aa-e8b8-4437-949b-e0e697c14d8f', 'Tuck Jumps', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Calves"}', 'Jump straight up and tuck your knees towards your chest, then land softly and repeat.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('a1e40d11-4bd5-4e0d-bb59-de274955dccb', 'Windshield Wipers', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Obliques, Rectus Abdominis"}', 'Lie on your back with legs extended towards the ceiling. Rotate your legs side to side like windshield wipers.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b0ec175d-d325-4e33-8b4e-aa5c9c0a229c', 'Dumbbell Shrugs', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'HOLD'::"MovementType", '{"Trapezius"}', 'Stand with a dumbbell in each hand at your sides. Shrug your shoulders towards your ears, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('98b6b465-b7c4-41bb-97ab-6d949df1e37e', 'Sled Push', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Shoulders"}', 'Push a weighted sled across a flat surface, keeping your back straight and core tight.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('59eaf956-7f44-4f3a-867d-998b93944c34', 'Cable Bicep Curl', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Biceps, Forearms"}', 'Stand facing a cable machine with the handle attached to a low pulley. Curl the handle towards your shoulders, then lower it back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('ab921ceb-31fd-4988-a103-7f6db5c0f85f', 'Dumbbell Kickback', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Triceps"}', 'Bend at the waist with a dumbbell in each hand. Extend your arms straight back, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('a1e850b3-0d99-47a8-aa03-5b9f9241f7e4', 'Flutter Kicks', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Lie on your back with legs extended. Lift your feet off the ground and alternate kicking them up and down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('1457b5a7-6e5e-4ffc-91a4-284721095a2c', 'High Knees', 'CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Hip Flexors, Calves"}', 'Run in place while driving your knees towards your chest as high as possible.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('2c23389f-1736-4c68-9930-0e987c041aac', 'Sledgehammer Slams', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Core, Shoulders, Glutes"}', 'Lift a sledgehammer overhead and slam it down onto a tire or other soft surface.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('a319e56d-d85b-449b-8700-14a829a84d7d', 'Lateral Step-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Step up onto a bench or box laterally with one foot, then bring the other foot up to meet it. Step back down and repeat.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('f10eef8c-7fa1-46da-b291-b57b118a1f4a', 'Cable Chest Press', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Stand in front of a cable machine with handles at chest height. Press the handles forward, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('47664290-9b0b-46b1-990c-3cebbfd3edf8', 'TRX Rows', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Grip the TRX handles and lean back, keeping your body straight. Pull your chest towards the handles, then lower back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('0de540a4-95ef-4d20-9205-df2cf673c971', 'Medicine Ball Russian Twists', 'STRENGTH'::"ExerciseType", 'MEDICINE_BALL'::"EquipmentType", 'CORE'::"BodyPart", 'PUSH'::"MovementType", '{"Obliques, Rectus Abdominis"}', 'Sit on the floor with knees bent, holding a medicine ball. Twist your torso to each side, tapping the ball on the floor.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('6237c07d-7362-4252-965e-69873269c387', 'Pendlay Row', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Bend over with a barbell on the floor. Row the barbell to your torso, then lower it back to the floor each rep.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('2db9946c-0941-438d-a4fd-0fa005cda961', 'Side Plank with Leg Lift', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Obliques, Glutes, Shoulders"}', 'In a side plank position, lift your top leg towards the ceiling, then lower it back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('e6556444-fa0c-4e79-b56b-6160d903eaf9', 'Hip Abduction', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Hip Flexors"}', 'Sit on a hip abduction machine and press your legs apart against the resistance, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5d4f78fe-0a8d-4ab9-91f7-8b771f45a69e', 'Dumbbell Front Raise', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids"}', 'Stand with a dumbbell in each hand, palms facing your thighs. Raise your arms in front of you until they are parallel to the floor.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('d81ea029-6f91-4717-a905-f3d107add1c3', 'Chin-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Grip a pull-up bar with an underhand grip. Pull your body up until your chin is above the bar, then lower back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('70443c74-0eff-4bb6-b68b-a9e539b42719', 'Box Squat', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Stand in front of a box with a barbell on your shoulders. Squat down until you sit on the box, then stand back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('07e3a338-235a-495a-8db8-d01ecea5822b', 'Battle Rope Waves', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Forearms, Core"}', 'Hold the ends of the ropes and create waves by alternating your arms up and down rapidly.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b856bd42-eef9-4d19-b7a4-42dea3c003ca', 'Zercher Squat', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Hold a barbell in the crook of your elbows. Squat down until your thighs are parallel to the floor, then push back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('f7bfccf5-0345-4225-aef5-b5558c404911', 'Walking Lunges', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Step forward into a lunge, then bring your back foot forward to step into the next lunge.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('c097a480-cc24-43e9-ad24-a18e3461bb68', 'Kettlebell Snatch', 'STRENGTH'::"ExerciseType", 'KETTLEBELL'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Shoulders, Triceps"}', 'Swing a kettlebell between your legs, then pull it overhead in one motion.', NOW(), NOW());
