INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('20fcde64-29d7-442b-92dc-2d7779660de6', 'Decline Sit-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Lie on a decline bench and sit up, bringing your chest towards your knees.', NOW(), NOW());
