INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('42b3568d-3f44-41a1-aecb-7dd20b749182', 'Dead Bug', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Lie on your back with arms extended towards the ceiling. Lower opposite arm and leg towards the floor while keeping your back flat.', NOW(), NOW());
