INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('702d71f8-5d1e-4633-8cac-1f004f630e62', 'Incline Barbell Bench Press', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Lie on an incline bench with a barbell. Press the bar up and together over your chest, then lower it back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('b073fad0-8c33-4d70-a08d-b0dc4eda4847', 'Kettlebell Goblet Squat', 'STRENGTH'::"ExerciseType", 'KETTLEBELL'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Hold a kettlebell at chest level and squat down as if sitting in a chair. Return to standing.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('211a9698-f215-4536-8d23-99c09db02271', 'Dumbbell Thrusters', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Shoulders"}', 'Hold a dumbbell in each hand at shoulder height. Squat down, then push through your heels to stand up and press the weights overhead.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('ebe66398-f8cd-44f8-8c31-a5ee253e89a9', 'Lying Leg Curl', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Hamstrings"}', 'Lie face down on a leg curl machine and curl the pad towards your glutes, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('a9914d41-1fd8-4ad5-805b-003281bbff01', 'Dumbbell Hammer Curl', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Biceps, Forearms"}', 'Stand with feet shoulder-width apart, holding a dumbbell in each hand with a neutral grip. Curl the weights up towards your shoulders.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('88e027ab-0a47-416f-ac7c-7b06584962d7', 'Landmine Squat Press', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Shoulders"}', 'Hold the end of a barbell anchored in a landmine attachment. Squat down, then push through your heels to stand up and press the bar overhead.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('854a5877-5511-411c-b081-e304318e3d98', 'Zottman Curl', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Biceps, Forearms"}', 'Stand with feet shoulder-width apart, holding a dumbbell in each hand. Curl the weights up with a supinated grip, then rotate your wrists and lower them with a pronated grip.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('6544ebee-7b20-4f3b-8804-a546bbad450d', 'Cable Crunch', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis"}', 'Kneel in front of a cable machine with a rope attachment. Crunch down, bringing your elbows towards your knees while keeping your back straight.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('8a92fb25-c0d6-4b6d-99b7-ee0954f73ef0', 'Stability Ball Pike', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Start in a plank position with your feet on a stability ball. Roll the ball towards your hands by piking your hips towards the ceiling.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('37e47623-8645-4346-a17b-3683585a4690', 'Standing Calf Raise', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Calves"}', 'Stand with the balls of your feet on the edge of a step. Raise your heels as high as possible, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('05273458-1db4-49ea-9b9e-a98e96cc4a9c', 'Cable Kickback', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Triceps"}', 'Stand facing a cable machine with a handle attached to the low pulley. Extend your arm straight back, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('604a4826-6fbe-4da4-9b4f-fddca4701e48', 'Spider Push-Ups', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids, Obliques"}', 'Start in a high plank position. As you lower your body, bring one knee towards your elbow, then push back up and switch sides.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('84704dbb-e603-4814-b074-7891a60839ec', 'Resistance Band Chest Press', 'STRENGTH'::"ExerciseType", 'RESISTANCE_BAND'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Attach a resistance band to a sturdy anchor behind you. Press the handles forward until your arms are fully extended.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('38559fad-0299-461e-9095-eda8a0a2d3af', 'One-Arm Dumbbell Row', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Place one knee and hand on a bench for support. Row the dumbbell towards your torso with the other hand.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('7e2748ea-6143-40e4-9f32-a381e22c4e63', 'Incline Chest Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Lie on an incline bench with a dumbbell in each hand. Press the weights up and together over your chest, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('320c0f35-9ff5-457b-bf37-268f2bedcc4b', 'Machine Preacher Curl', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Biceps"}', 'Sit at a preacher curl machine with your arms on the pad. Curl the handle towards your shoulders, then lower it back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('7616c713-6b53-499d-af92-d80404ed10f8', 'Hanging Knee Raises', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Hang from a pull-up bar and tuck your knees towards your chest, then slowly lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('e3257753-2cdb-4a69-8e2d-3938e77f1104', 'Decline Dumbbell Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Lie on a decline bench with a dumbbell in each hand. Lower the weights to your chest, then press them back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('1c11143d-300f-4111-a61a-8cfc9ee953fb', 'Glute Kickback', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Hamstrings"}', 'Start on all fours and kick one leg straight back, squeezing your glutes at the top of the movement.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('9393dca3-fa4b-410e-b42d-902ffbd390e2', 'Machine Chest Press', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Sit at a chest press machine with your feet flat on the floor. Press the handles forward until your arms are fully extended.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5c3e80b9-d3cc-41c4-90b8-3f32cc443f99', 'Single-Leg Squat', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Stand on one leg with the other leg extended in front of you. Lower your hips until your thigh is parallel to the floor, then push back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('32b705bf-5ce5-4947-81a7-f42183f54e64', 'Push-Up to Row', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Latissimus Dorsi"}', 'Start in a high plank position with a dumbbell in each hand. Perform a push-up, then row each dumbbell towards your torso.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('a5c46bb8-bf87-4bd0-960a-bba45649da20', 'Smith Machine Row', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Stand with feet shoulder-width apart, bend forward at the hips, and row the bar towards your torso.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('3e8d6865-b52c-40ce-b019-a29f44ff3400', 'Lat Pullover', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Pectorals, Triceps"}', 'Lie on a bench holding a dumbbell over your chest. Lower the weight behind your head, then pull it back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('cdde7d1d-e2de-4ba4-9148-8402eede98aa', 'Smith Machine Shoulder Press', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Triceps"}', 'Sit on a bench under a Smith machine bar. Press the bar overhead until your arms are fully extended.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('091f38a1-ece2-48e3-8e27-8b359a763aea', 'Cable Woodchopper', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'PUSH'::"MovementType", '{"Obliques, Rectus Abdominis"}', 'Stand sideways to a cable machine with the handle at the high pulley. Pull the handle down across your body in a chopping motion.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('4501671a-7640-4241-b74c-d523dbd35d1d', 'Machine Back Extension', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Lower Back, Glutes, Hamstrings"}', 'Sit on a back extension machine with your feet braced. Extend your hips to lift your torso, then lower back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('9e4ad48f-84b6-47ee-b1a6-462181e470e4', 'Prone Leg Curl', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Hamstrings"}', 'Lie face down on a leg curl machine and curl the pad towards your glutes, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('8811bccd-2a9b-4249-becd-b6930aa46045', 'Seated Dumbbell Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Triceps"}', 'Sit on a bench with a dumbbell in each hand at shoulder height. Press the weights overhead until your arms are fully extended.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('cecbece4-577f-459a-8e0d-5b4f09c1653b', 'Weighted Plank', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Obliques, Shoulders"}', 'Start in a forearm plank position with a weight plate on your back. Hold the position while keeping your body straight.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('cdec1221-7141-4736-9df1-0daa69644e3f', 'Step Mill', 'CARDIO'::"ExerciseType", 'MACHINE'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings, Calves"}', 'Step continuously on a revolving staircase, keeping a steady pace.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('4eebf3a8-398a-4ca9-860a-32bd77adc556', 'Standing Resistance Band Row', 'STRENGTH'::"ExerciseType", 'RESISTANCE_BAND'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Attach a resistance band to a sturdy anchor. Pull the handles towards your torso, keeping your elbows close to your body.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('9daaff1f-67ab-46bb-bf53-aa213718b7a6', 'Dumbbell Lunge', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Hold a dumbbell in each hand and step forward into a lunge. Push back to the starting position and repeat on the other leg.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('476c92a4-063c-49fb-a847-9dd792d007bc', 'Reverse Curl', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Biceps, Forearms"}', 'Stand with feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip. Curl the weights up towards your shoulders.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('2f0158dd-ab64-484a-abf1-12d830a4f855', 'Banded Pull-Up', 'STRENGTH'::"ExerciseType", 'RESISTANCE_BAND'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Loop a resistance band around a pull-up bar and place your knees in the band. Pull your body up until your chin is above the bar.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('a0f26fa6-b789-44ea-87b3-38fca79307c7', 'Cable Face Pull', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Rear Deltoids, Trapezius, Rhomboids"}', 'Attach a rope handle to a high cable pulley. Pull the handle towards your face, leading with your elbows.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('e5af7ccc-b037-4813-9e18-669d5770bf7f', 'Turkish Get-Up', 'STRENGTH'::"ExerciseType", 'KETTLEBELL'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'HOLD'::"MovementType", '{"Core, Shoulders, Glutes"}', 'Lie on your back holding a kettlebell overhead. Stand up while keeping the kettlebell above your head, then return to lying.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('8cdc4a81-a9fd-4eb5-892e-8b276f601cc6', 'Weighted Russian Twists', 'STRENGTH'::"ExerciseType", 'MEDICINE_BALL'::"EquipmentType", 'CORE'::"BodyPart", 'PUSH'::"MovementType", '{"Obliques, Rectus Abdominis"}', 'Sit on the floor with knees bent, holding a medicine ball. Twist your torso to each side, tapping the ball on the floor.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('987df3ef-ebff-4dd3-87c1-eae93c65a29d', 'Cable Front Raise', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids"}', 'Stand facing a cable machine with the handle at the low pulley. Raise the handle in front of you until your arm is parallel to the floor.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('1aab13a5-de4c-4fea-8d74-42bc6ea45259', 'Reverse Crunch', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Rectus Abdominis, Hip Flexors"}', 'Lie on your back with legs extended towards the ceiling. Lift your hips off the ground, bringing your knees towards your chest.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('4ec2107a-93c7-48c4-a71f-27c406524cd5', 'Cable Tricep Kickback', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Triceps"}', 'Stand facing a cable machine with a handle attached to the low pulley. Extend your arm straight back, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('3a11529d-807a-49eb-8d7b-2245523df2d9', 'Copenhagen Plank', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'HOLD'::"MovementType", '{"Obliques, Adductors"}', 'Lie on your side with your top leg on a bench and your bottom leg extended. Lift your hips to form a straight line from head to heels.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5c114b4e-9cf4-4398-ab65-95d48dda4ff9', 'Smith Machine Incline Press', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Lie on an incline bench under a Smith machine bar. Press the bar up and together over your chest, then lower it back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('e5a0ee1f-e0ad-44ab-8170-7d5dc61f7db2', 'Cable Lat Pulldown', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Sit at a lat pulldown machine, grasp the bar with a wide grip, and pull it down to your chest. Slowly return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('d0099fb9-17b8-4434-aefa-3505f76ba86d', 'Cable Side Lunge', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Adductors"}', 'Attach a handle to a low pulley and stand to the side of the cable machine. Step out into a side lunge, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('74b55022-a7fc-4595-ba80-084f9d13d528', 'Dumbbell Bent-Over Row', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Stand with feet shoulder-width apart, bend forward at the hips, and row the dumbbells towards your torso.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('f8c9ab02-aeb5-4564-b172-c23ed9357e87', 'Lateral Lunge', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Adductors"}', 'Step out to the side, bending one knee while keeping the other leg straight. Push back to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('dcaaf53e-ea91-4966-9bdd-67d78a1c38e9', 'Seated Machine Row', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Sit at a rowing machine with feet braced. Pull the handles towards your torso, then slowly return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('8cc143cf-4488-4915-8701-fb603cbbf764', 'Decline Russian Twist', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'CORE'::"BodyPart", 'PUSH'::"MovementType", '{"Obliques, Rectus Abdominis"}', 'Sit on a decline bench with your knees bent. Twist your torso to each side, tapping your hands on the floor.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('e2e8f7b1-b72a-461f-b175-2bbdc19080a0', 'Deadlift High Pull', 'STRENGTH'::"ExerciseType", 'BARBELL'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Glutes, Hamstrings, Shoulders"}', 'Start with a barbell on the ground, perform a deadlift, and as you stand up, pull the barbell up towards your chest.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('2a932b3e-b7e4-4084-a49a-eccc00d98232', 'Reverse Grip Lat Pulldown', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Sit at a lat pulldown machine with a reverse grip. Pull the bar down to your chest, then slowly return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('67f8bbd9-99d8-4e35-a123-b1f43199ff9d', 'Cable Lateral Lunge', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Adductors"}', 'Attach a handle to a low pulley and stand to the side of the cable machine. Step out into a side lunge, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('e2c49a67-fb09-45e9-8e20-a1ef1159c376', 'Pike Push-Up', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Deltoids, Triceps"}', 'Start in a downward dog position with your hips raised. Lower your head towards the floor, then push back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('850ca862-85b0-49ae-80ee-32bbdec6e68c', 'One-Arm Dumbbell Snatch', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Shoulders, Triceps"}', 'Start with a dumbbell between your feet. Explosively pull the dumbbell up and overhead in one motion.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5b14f0ab-2f4c-41c5-adfe-7aaab1b5cd91', 'Cable Front Squat', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Attach a rope handle to a low pulley and stand facing the cable machine. Squat down while holding the rope at chest height.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('0f07e306-32b4-4a91-aa9e-c24e57a8fa43', 'Tire Flip', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Glutes, Quadriceps, Hamstrings, Shoulders"}', 'Squat down and grab the edge of a tire. Lift the tire and flip it forward.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('4724e68f-4cfa-432e-9741-aad8a5ebca71', 'Smith Machine Calf Raise', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Calves"}', 'Stand under the bar of a Smith machine with the balls of your feet on a step. Raise your heels as high as possible, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('c0165b09-da10-40f0-8799-a2e7a08d6c3d', 'Pistol Squat to Box', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'LOWER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Quadriceps, Glutes, Hamstrings"}', 'Stand on one leg in front of a box. Lower your hips until you sit on the box, then stand back up.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('6c2f3744-6861-420f-9f87-83a01a8ef65e', 'Standing Chest Fly', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Deltoids"}', 'Stand in the middle of a cable machine with handles in each hand. Bring the handles together in front of your chest, then return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('a03c53b6-b1fd-449c-bb84-4d5ae8ce728e', 'Sled Drag', 'STRENGTH_CARDIO'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'FULL_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Glutes, Quadriceps, Hamstrings, Shoulders"}', 'Attach a harness to a sled and drag it across a flat surface, walking or running backwards.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('3e5ec97c-d6d7-4be2-b492-e0e69b8aabff', 'Cable Hammer Curl', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Biceps, Forearms"}', 'Stand facing a cable machine with the handle attached to the low pulley. Curl the handle towards your shoulders with a neutral grip.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('aa9ca95f-9f9f-4fe9-a36e-858cd65ef540', 'Cable Tricep Overhead Extension', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Triceps"}', 'Stand facing away from a cable machine with the handle attached to the low pulley. Extend the handle overhead until your arms are fully extended.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('31c58c98-50bd-4812-bf0e-ab96f3250aa9', 'Seated Cable Row', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Sit at a cable row machine with feet braced. Pull the handle towards your torso, then slowly return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('cbb30e90-3925-4e20-8a4a-6d8592ede22e', 'Lying Dumbbell Tricep Extension', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Triceps"}', 'Lie on a bench with a dumbbell in each hand. Lower the weights towards your head by bending your elbows, then extend your arms back to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('409f8805-bd24-4b0d-be45-b97b252176e2', 'Weighted Pull-Up', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Hang a weight from your waist and perform a pull-up, bringing your chin above the bar.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('dac59bfb-15ce-4e69-a2cd-6b585c8b7976', 'Incline Dumbbell Row', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Lie face down on an incline bench with a dumbbell in each hand. Row the weights towards your torso, then lower them back down.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('e1f16df7-5546-4eda-8c20-d1eaff39e70b', 'Machine Lat Pulldown', 'STRENGTH'::"ExerciseType", 'MACHINE'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Sit at a lat pulldown machine with a wide grip. Pull the bar down to your chest, then slowly return to the starting position.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('5a908f8f-97dc-4f75-9c22-a7033dfaf534', 'One-Arm Cable Row', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Latissimus Dorsi, Biceps"}', 'Stand facing a cable machine with the handle attached to the low pulley. Row the handle towards your torso with one hand.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('3b4a30dd-55a7-4731-923a-b56017366d7f', 'Face Pull', 'STRENGTH'::"ExerciseType", 'BODYWEIGHT'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PULL'::"MovementType", '{"Rear Deltoids, Trapezius, Rhomboids"}', 'Attach a rope handle to a high cable pulley. Pull the handle towards your face, leading with your elbows.', NOW(), NOW());
INSERT INTO exercises (id, exercise_name, type_of_activity, type_of_equipment, body_part, type, muscle_groups_activated, instructions, created_at, updated_at) VALUES ('04b8ee35-3422-46e1-be29-2c29ae522226', 'Dumbbell Bench Press', 'STRENGTH'::"ExerciseType", 'DUMBBELLS'::"EquipmentType", 'UPPER_BODY'::"BodyPart", 'PUSH'::"MovementType", '{"Pectorals, Triceps, Deltoids"}', 'Lie on a bench with a dumbbell in each hand. Press the weights up and together over your chest, then lower them back down.', NOW(), NOW());